def process(value, min, max):
    if value is None:
        return 0.0
    min_val = min if min is not None else 0.0
    max_val = max if max is not None else 1.0
    return min_val if value < min_val else (max_val if value > max_val else value)

def process(value):
    import math
    v = value if value is not None else 0.0
    return math.sqrt(abs(v))

def process(value, decimals):
    v = value if value is not None else 0.0
    d = int(decimals) if decimals is not None else 0
    return round(v, d)
